import { ethers } from 'ethers';

declare class HttpClient {
    private readonly baseUrl;
    private token;
    constructor(baseUrl: string);
    setToken(token: string): void;
    getToken(): string | null;
    clearToken(): void;
    private headers;
    get<T>(path: string): Promise<T>;
    post<T>(path: string, body: unknown): Promise<T>;
    private handleResponse;
}

declare class Auth {
    private readonly http;
    constructor(http: HttpClient);
    getNonce(address: string): Promise<string>;
    /** EIP-191 login with ethers signer. Stores JWT automatically. */
    login(signer: ethers.Signer): Promise<string>;
    /** If you handle signing externally. */
    loginRaw(address: string, nonce: string, signature: string): Promise<string>;
    setToken(token: string): void;
    getToken(): string | null;
}

interface ChainEntry {
    chain_id: string;
    chain_type: "evm";
    address: string;
    vault_address?: string;
}
interface PaymentOption {
    token: string;
    type: "x402" | "native";
    chain_type: "evm";
    receiver_address?: string;
    chains: ChainEntry[];
}
interface RegistryResponse {
    payment_options: PaymentOption[];
    vault_abi: string;
}
interface NonceResponse {
    nonce: string;
}
interface LoginResponse {
    token: string;
}
interface QuoteRequest {
    payment_coin?: string;
    payer_address: string;
    payment_chain?: string;
    payment_chain_type?: "evm";
    tx_object: string;
    dest_chain_id?: string;
    dest_chain_type?: "evm";
}
interface QuoteResponse {
    digest: string;
    payment_amount: string;
    payment_mode: "x402" | "vault";
    payment_to: string;
    gas_amount: string;
    expires_at: number;
}
interface X402Payload {
    digest: string;
    payment_mode: "x402";
    v: number;
    r: string;
    s: string;
    nonce: string;
    valid_after: number;
    valid_before: number;
}
interface VaultPayload {
    digest: string;
    payment_mode: "vault";
    tx_hash: string;
}
interface PaymentSubmitResponse {
    status: string;
}
type TxStatus = "pending" | "completed" | "failed" | "expired";
interface StatusResponse {
    status: TxStatus;
    digest: string;
    signature?: string;
    error?: string;
}
declare class UGFError extends Error {
    readonly code?: string | undefined;
    readonly statusCode?: number | undefined;
    constructor(message: string, code?: string | undefined, statusCode?: number | undefined);
}
declare class UGFAuthError extends UGFError {
    constructor(message: string);
}
declare class UGFTimeoutError extends UGFError {
    constructor(message: string);
}
declare class UGFSignatureError extends UGFError {
    constructor(message: string);
}
interface UGFClientConfig {
    baseUrl?: string;
    token?: string;
}

interface PollOptions {
    maxAttempts?: number;
    intervalMs?: number;
    onTick?: (status: StatusResponse, attempt: number) => void;
}
declare class Status {
    private readonly http;
    constructor(http: HttpClient);
    get(digest: string): Promise<StatusResponse>;
    poll(digest: string, opts?: PollOptions): Promise<StatusResponse>;
}

declare class EvmChain {
    private readonly status;
    private readonly http;
    constructor(http: HttpClient);
    waitForCompletion(digest: string, opts?: PollOptions): Promise<StatusResponse>;
    /**
     * Poll until UGF sponsorship completes, then send the user tx with gas
     * automatically fitted to the sponsored ETH balance.
     *
     * @param buildTx - Return a TransactionRequest (no gas fields needed).
     *                  SDK estimates gas, caps gasPrice to sponsored budget, sends as legacy tx.
     */
    sponsorAndExecute(digest: string, signer: ethers.Signer, buildTx: (signer: ethers.Signer) => Promise<ethers.TransactionRequest>, opts?: PollOptions): Promise<{
        userTxHash: string;
    }>;
}

declare class Registry {
    private readonly http;
    private cache;
    constructor(http: HttpClient);
    get(): Promise<RegistryResponse>;
    invalidate(): void;
    /** Find a payment option by token symbol e.g. "TYI_MOCK_USD" */
    getOption(token: string): Promise<PaymentOption>;
    /** Get chain entry for a token on a specific chain_id */
    getChainEntry(token: string, chainId: string): Promise<ChainEntry>;
    /** Get vault ABI parsed */
    getVaultAbi(): Promise<object[]>;
}

interface X402Options {
    validForSeconds?: number;
}
declare class X402Payment {
    private readonly http;
    private readonly registry;
    constructor(http: HttpClient, registry: Registry);
    sign(quote: QuoteResponse, signer: ethers.Signer, provider: ethers.Provider, opts?: X402Options): Promise<X402Payload>;
    submit(payload: X402Payload): Promise<PaymentSubmitResponse>;
    signAndSubmit(quote: QuoteResponse, signer: ethers.Signer, provider: ethers.Provider, opts?: X402Options): Promise<PaymentSubmitResponse>;
    execute(params: {
        quote: QuoteResponse;
        signer: ethers.Signer;
        token?: string;
        opts?: X402Options;
    }): Promise<PaymentSubmitResponse>;
}

declare class VaultPayment {
    private readonly http;
    private readonly registry;
    constructor(http: HttpClient, registry: Registry);
    pay(quote: QuoteResponse, signer: ethers.Signer, chainId: string, token: string): Promise<VaultPayload>;
    submit(payload: VaultPayload): Promise<PaymentSubmitResponse>;
    payAndSubmit(quote: QuoteResponse, signer: ethers.Signer, chainId: string, token: string): Promise<PaymentSubmitResponse>;
}

declare class Quote {
    private readonly http;
    constructor(http: HttpClient);
    get(req: QuoteRequest): Promise<QuoteResponse>;
}

declare class UGFClient {
    private readonly http;
    readonly auth: Auth;
    readonly quote: Quote;
    readonly status: Status;
    readonly registry: Registry;
    readonly payment: {
        x402: X402Payment;
        vault: VaultPayment;
    };
    readonly chains: {
        evm: EvmChain;
    };
    constructor(config?: UGFClientConfig);
}

declare const BASE_SEPOLIA_CHAIN_ID = "84532";
declare const BASE_SEPOLIA_CHAIN_TYPE = "evm";
declare const TYI_USD_PAYMENT_COIN = "TYI_MOCK_USD";

export { BASE_SEPOLIA_CHAIN_ID, BASE_SEPOLIA_CHAIN_TYPE, type ChainEntry, type LoginResponse, type NonceResponse, type PaymentOption, type PaymentSubmitResponse, type PollOptions, type QuoteRequest, type QuoteResponse, type RegistryResponse, type StatusResponse, TYI_USD_PAYMENT_COIN, type TxStatus, UGFAuthError, UGFClient, type UGFClientConfig, UGFError, UGFSignatureError, UGFTimeoutError, type VaultPayload, type X402Options, type X402Payload };
